@using sv_6fee140eb0df4e72bc9ec7173153b536.Services

@inject IHttpContextAccessor HttpContextAccessor
@inject WizardStateStore StateStore

@{
    var steps = new (string Href, string Label)[]
    {
        ("apply/personal-info", "Personal Info"),
        ("apply/experience", "Experience"),
        ("apply/references", "References"),
        ("apply/review", "Review"),
    };

    var path = HttpContextAccessor.HttpContext?.Request.Path.Value ?? "";
    var currentStep = -1;
    for (int i = 0; i < steps.Length; i++)
    {
        if (path.Contains(steps[i].Href, StringComparison.OrdinalIgnoreCase))
        {
            currentStep = i + 1;
            break;
        }
    }

    var sessionId = HttpContextAccessor.HttpContext?.Session.Id ?? "";
    var formData = !string.IsNullOrEmpty(sessionId) ? StateStore.GetOrCreate(sessionId) : null;
    var completedSteps = formData?.CompletedSteps ?? [];
}

@if (currentStep > 0)
{
    <div class="wizard-progress mb-4">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <strong>Step @currentStep of @steps.Length</strong>
            <span class="text-muted">@steps[currentStep - 1].Label</span>
        </div>
        <div class="d-flex gap-2">
            @for (int i = 0; i < steps.Length; i++)
            {
                var step = i + 1;
                var isActive = step == currentStep;
                var isCompleted = completedSteps.Contains(step);
                var cssClass = isActive ? "bg-primary" : isCompleted ? "bg-success" : "bg-secondary opacity-25";

                <a href="@steps[i].Href"
                   class="flex-fill rounded text-center text-white text-decoration-none py-1 @cssClass"
                   style="font-size: 0.85rem;">
                    @steps[i].Label
                </a>
            }
        </div>
    </div>
}

@page "/apply/personal-info"
@rendermode InteractiveServer

@using sv_6fee140eb0df4e72bc9ec7173153b536.Services
@inject WizardStateStore StateStore
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Navigation

<PageTitle>Apply - Personal Info</PageTitle>
<h3>Step 1: Personal Information</h3>

<EditForm Model="@_model" OnValidSubmit="HandleNext" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="_model.FullName" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" type="email" @bind-Value="_model.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next &raquo;</button>
</EditForm>

@code {
    private PersonalInfoModel _model = new();
    private string _sessionId = "";

    protected override void OnInitialized()
    {
        _sessionId = HttpContextAccessor.HttpContext?.Session.Id ?? "";
        if (!string.IsNullOrEmpty(_sessionId))
        {
            var data = StateStore.GetOrCreate(_sessionId);
            _model.FullName = data.FullName;
            _model.Email = data.Email;
        }
    }

    private void HandleNext()
    {
        if (string.IsNullOrEmpty(_sessionId)) return;

        var data = StateStore.GetOrCreate(_sessionId);
        data.FullName = _model.FullName;
        data.Email = _model.Email;
        data.CompletedSteps.Add(1);
        Navigation.NavigateTo("apply/experience");
    }

    private class PersonalInfoModel
    {
        public string FullName { get; set; } = "";
        public string Email { get; set; } = "";
    }
}

