@rendermode InteractiveServer

@using sv_6fee140eb0df4e72bc9ec7173153b536.Services
@inject WizardStateStore StateStore
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Navigation

<PageTitle>Apply - Review</PageTitle>
<h3>Step 4: Review Your Application</h3>

@if (_data is not null)
{
    <div class="card mb-3 p-3">
        <h5>Personal Information</h5>
        <p><strong>Name:</strong> @_data.FullName</p>
        <p><strong>Email:</strong> @_data.Email</p>
        <a href="apply/personal-info" class="btn btn-sm btn-outline-secondary">Edit</a>
    </div>

    <div class="card mb-3 p-3">
        <h5>Experience</h5>
        @if (_data.JobHistory.Count == 0)
        {
            <p class="text-muted">No job history entered.</p>
        }
        else
        {
            @foreach (var job in _data.JobHistory)
            {
                <div class="mb-2">
                    <strong>@job.Title</strong> at @job.Company (@job.Years years)
                </div>
            }
        }
        <a href="apply/experience" class="btn btn-sm btn-outline-secondary">Edit</a>
    </div>

    <div class="card mb-3 p-3">
        <h5>References</h5>
        @if (_data.References.Count == 0)
        {
            <p class="text-muted">No references entered.</p>
        }
        else
        {
            @foreach (var r in _data.References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> — @r.Relationship, @r.Phone
                </div>
            }
        }
        <a href="apply/references" class="btn btn-sm btn-outline-secondary">Edit</a>
    </div>

    <div class="d-flex gap-2">
        <button type="button" class="btn btn-secondary" @onclick="HandleBack">&laquo; Back</button>
        <button type="button" class="btn btn-success" @onclick="HandleSubmit">Submit Application</button>
    </div>

    @if (_submitted)
    {
        <div class="alert alert-success mt-3">
            Your application has been submitted successfully!
        </div>
    }
}

@code {
    private WizardFormData? _data;
    private string _sessionId = "";
    private bool _submitted;

    protected override void OnInitialized()
    {
        _sessionId = HttpContextAccessor.HttpContext?.Session.Id ?? "";
        if (!string.IsNullOrEmpty(_sessionId))
        {
            _data = StateStore.GetOrCreate(_sessionId);
            _data.CompletedSteps.Add(4);
        }
    }

    private void HandleBack()
    {
        Navigation.NavigateTo("apply/references");
    }

    private void HandleSubmit()
    {
        _submitted = true;
        // In a real app, persist the data and clear the wizard state:
        // StateStore.Remove(_sessionId);
    }
}
